// // This module decrements a 4-bit counter on each positive edge of the clock when enabled, and resets to 15 when the reset signal is asserted.
module counter_4bit 
(
  input clk,
  input reset,
  input enable,

  output reg [3:0] q
);

  always @(posedge clk) begin
    if (reset)
      q <= 4'b0000;
    else if (enable)
      q <= q + 1;
  end

endmodule
